# Car module: Concrete vehicle implementations

from vehicle import Vehicle, IMaintenance

class Car(Vehicle, IMaintenance):
    num_doors: int
    is_electric: bool

    def __init__(self, brand: str, model: str, year: int, doors: int, electric: bool):
        super().__init__(brand, model, year)
        self.num_doors = doors
        self.is_electric = electric

    @override
    def get_vehicle_type(self) -> str:
        if self.is_electric:
            return "Electric Car"
        return "Gas Car"

    def perform_maintenance(self) -> str:
        if self.is_electric:
            return "Check battery and electric motor"
        return "Change oil and check engine"

class Motorcycle(Vehicle, IMaintenance):
    has_sidecar: bool
    engine_cc: int

    def __init__(self, brand: str, model: str, year: int, sidecar: bool, cc: int):
        super().__init__(brand, model, year)
        self.has_sidecar = sidecar
        self.engine_cc = cc

    @override
    def get_vehicle_type(self) -> str:
        return "Motorcycle"

    def perform_maintenance(self) -> str:
        return f"Service {self.engine_cc}cc engine"

