# Fleet module: Vehicle management

from vehicle import Vehicle
from car import Car, Motorcycle

class FleetManager:
    fleet_name: str
    total_vehicles: int

    def __init__(self, name: str):
        self.fleet_name = name
        self.total_vehicles = 0

    def register_vehicle(self, vehicle: Vehicle) -> None:
        self.total_vehicles += 1

    def get_fleet_summary(self) -> str:
        return f"Fleet '{self.fleet_name}' has {self.total_vehicles} vehicles"
